import io.grpc.stub.StreamObserver;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileUploadServiceImpl extends FileUploadServiceGrpc.FileUploadServiceImplBase {

    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadResponse> responseObserver) {
        return new StreamObserver<FileChunk>() {
            private Path tempFile;
            private long totalBytesReceived = 0;

            @Override
            public void onNext(FileChunk fileChunk) {
                if (tempFile == null) {
                    try {
                        tempFile = Files.createTempFile("upload", ".tmp");
                    } catch (IOException e) {
                        responseObserver.onError(e);
                        return;
                    }
                }

                try {
                    Files.write(tempFile, fileChunk.getData().toByteArray(), java.nio.file.StandardOpenOption.CREATE, java.nio.file.StandardOpenOption.APPEND);
                    totalBytesReceived += fileChunk.getData().size();
                } catch (IOException e) {
                    responseObserver.onError(e);
                    return;
                }
            }

            @Override
            public void onError(Throwable t) {
                if (tempFile != null) {
                    try {
                        Files.deleteIfExists(tempFile);
                    } catch (IOException e) {
                        // Ignore
                    }
                }
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                if (totalBytesReceived > MAX_MESSAGE_SIZE) {
                    responseObserver.onError(new IllegalArgumentException("Message size exceeds maximum allowed"));
                    return;
                }

                try {
                    Path finalFile = Paths.get("final_" + tempFile.getFileName());
                    Files.move(tempFile, finalFile);
                    responseObserver.onNext(UploadResponse.newBuilder().setMessage("File uploaded successfully").build());
                    responseObserver.onCompleted();
                } catch (IOException e) {
                    responseObserver.onError(e);
                }
            }
        };
    }

    private static final long MAX_MESSAGE_SIZE = 10 * 1024 * 1024; // 10MB
}